        {q:"The 'DOM' in web programming stands for:",o:["Document Object Model","Digital Online Media","Disk Operating Machine","Data Output Method"],a:"Document Object Model",e:"It represents the HTML structure as a tree of objects."},
        {q:"The 'DevOps' methodology combines:",o:["Art and Music","Development and Operations (IT)","Cooking and Baking","Math and Science"],a:"Development and Operations (IT)",e:"It aims for continuous integration and delivery."},
        {q:"The 'AI' branch 'Natural Language Processing' (NLP) deals with:",o:["Weather prediction","Human-computer language interaction (Chatbots)","Database design","Hardware repair"],a:"Human-computer language interaction (Chatbots)",e:"Siri and ChatGPT are examples of NLP."},
        {q:"The 'React.js' library is used for building:",o:["Databases","User interfaces (Front-end)","Backend servers","Games only"],a:"User interfaces (Front-end)",e:"Created by Facebook, it's component-based."},
        {q:"The 'Biometric' term 'False Acceptance Rate' (FAR) is:",o:["Speed of login","Rate of unauthorized users mistakenly granted access","Size of scanner","Price of device"],a:"Rate of unauthorized users mistakenly granted access",e:"Lower FAR means higher security."},
        {q:"In Python, the 'lambda' function is a:",o:["Large loop","Small anonymous function","Class definition","File name"],a:"Small anonymous function",e:"lambda x: x*2 is a simple, inline function."},
        {q:"The 'Cloud' service model 'SaaS' provides:",o:["Platform to build apps","Software over the internet on subscription","Virtual servers","Storage only"],a:"Software over the internet on subscription",e:"E.g., Google Workspace, Netflix."},
        {q:"The 'SQL' injection attack targets:",o:["Networks","Website databases (input fields)","Keyboards","Monitors"],a:"Website databases (input fields)",e:"Malicious SQL code manipulates the backend database."},
        {q:"The 'Ghana.GOV' portal is designed for:",o:["Social media","Centralized digital access to government services","Gaming","Movies"],a:"Centralized digital access to government services",e:"It provides e-services like birth certs, passport applications."},
        {q:"The 'Big O Notation' 'O(n)' describes:",o:["Constant time","Linear time complexity","Logarithmic time","Exponential time"],a:"Linear time complexity",e:"Runtime grows proportionally to input size."},
        {q:"The 'CSS Grid' layout system allows:",o:["Only vertical layouts","Two-dimensional responsive grid layouts","Only horizontal layouts","Only text styling"],a:"Two-dimensional responsive grid layouts",e:"It handles rows and columns simultaneously."},
        {q:"The 'API' stands for:",o:["Application Programming Interface","Apple Personal Intelligence","Automated Program Installer","Advanced Printer Ink"],a:"Application Programming Interface",e:"It allows different software components to communicate."},
        {q:"The 'Cybersecurity' term 'Zero-day' refers to:",o:["A bug that's been patched","A vulnerability unknown to the software vendor","A holiday","A weekend"],a:"A vulnerability unknown to the software vendor",e:"Attackers exploit it before a fix is available."},
        {q:"The 'python' command 'pip' is used to:",o:["Delete files","Install and manage Python packages","Create games","Edit images"],a:"Install and manage Python packages",e:"Python Package Installer downloads from PyPI."},
        {q:"The 'Machine Learning' technique using labeled data is:",o:["Unsupervised","Supervised","Reinforcement","None"],a:"Supervised",e:"The model learns from input-output pairs."},
        {q:"The 'Node.js' runtime executes JavaScript:",o:["In the browser only","On the server-side (Outside browser)","In Excel","In PDF"],a:"On the server-side (Outside browser)",e:"It uses the V8 engine for backend development."},
        {q:"The 'Data breach' prevention requires:",o:["Sharing passwords","Encryption and access controls","Public Wi-Fi","Old software"],a:"Encryption and access controls",e:"Protecting data confidentiality, integrity, and availability (CIA triad)."},
        {q:"The 'DNS over HTTPS' (DoH) aims to:",o:["Slow down internet","Encrypt DNS queries for privacy","Block websites","Monitor traffic"],a:"Encrypt DNS queries for privacy",e:"It prevents eavesdropping on browsing habits."},
        {q:"The 'Git' command 'clone' is used to:",o:["Delete a repository","Create a local copy of a remote repository","Save a file","Log out"],a:"Create a local copy of a remote repository",e:"git clone <url> downloads the project."},
        {q:"The 'CPU' component 'Cache' memory is:",o:["Slow and large","Very fast, small memory close to the CPU","External drive","Cloud"],a:"Very fast, small memory close to the CPU",e:"L1, L2, L3 caches reduce data access time."},
        {q:"The 'Digital Divide' refers to the gap between:",o:["Computers and phones","Those with and without access to digital technology","Students and teachers","Men and women"],a:"Those with and without access to digital technology",e:"Ghana's GIFEC works to bridge this gap."},
        {q:"The 'JavaScript' framework 'Vue.js' is used for:",o:["Backend only","Progressive front-end interfaces","Mobile apps only","Databases"],a:"Progressive front-end interfaces",e:"It is lightweight and flexible for building UIs."},
        {q:"The 'Public Key Infrastructure' (PKI) uses a pair of:",o:["One key","Public and Private keys","Three keys","No keys"],a:"Public and Private keys",e:"Asymmetric encryption relies on this key pair."},
        {q:"The 'Python' module 'os' provides functions for:",o:["Web scraping","Interacting with the operating system","Plotting","Gaming"],a:"Interacting with the operating system",e:"E.g., file handling, environment variables."},
        {q:"The 'Terahertz' (THz) frequencies are being researched for:",o:["2G networks","6G networks","Radio only","TV only"],a:"6G networks",e:"Future networks aim for ultra-high data rates."},
        {q:"The 'Deepfake' technology uses AI to:",o:["Calculate numbers","Synthesize realistic fake video/audio","Clean viruses","Print"],a:"Synthesize realistic fake video/audio",e:"It manipulates media to show events that never happened."},
        {q:"The 'Data structure' 'Queue' follows the principle:",o:["Last In First Out","First In First Out (FIFO)","Random","Sorted"],a:"First In First Out (FIFO)",e:"Like a line at the bank."},
        {q:"The 'Phishing' email might link to a website with a ___ URL.",o:["Legitimate","Slightly misspelled or fake domain","Short","Long"],a:"Slightly misspelled or fake domain",e:"E.g., faceb00k.com instead of facebook.com."},
        {q:"The 'Google Colab' provides:",o:["Driving directions","Free cloud-based Jupyter notebook environment for Python","Shopping deals","Music"],a:"Free cloud-based Jupyter notebook environment for Python",e:"It runs code on Google's servers, needing only a browser."},
        {q:"The 'Assembly language' is a step above:",o:["High-level language","Machine code","Python","Java"],a:"Machine code",e:"It uses mnemonics instead of binary."},
        {q:"The 'GDPR' in data privacy focuses on:",o:["Only Ghana","Protection of personal data (EU regulation)","Cars","Food safety"],a:"Protection of personal data (EU regulation)",e:"Ghana's Data Protection Act is similar."},
        {q:"The 'Thread' in a CPU allows:",o:["Physical wire","Multitasking (multiple execution sequences)","Storage","Cooling"],a:"Multitasking (multiple execution sequences)",e:"Hyper-threading improves parallel processing."}
